def add_all(*args):
    return sum(args)

print(add_all(1, 2, 3))
print(add_all(10, 20, 30, 40))

def print_info(**kwargs):
    for key, value in kwargs.items():
        print('{}: {}'.format(key, value))

print_info(name='小明', age=20)

exercises.solution:
def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)

print(factorial(5))
print(factorial(0))

def fizzbuzz(n):
    for i in range(1, n + 1):
        if i % 15 == 0:
            print('FizzBuzz')
        elif i % 3 == 0:
            print('Fizz')
        elif i % 5 == 0:
            print('Buzz')
        else:
            print(i)

fizzbuzz(15)
